//   {"id":1127,"subject":"化學","topic":"2A: Acids and Bases","type":"choice","text":"Which of the following reaction routes can best be used to prepare barium sulphate from barium carbonate?","points":5,"options":["BaCO₃(s) →(H₂SO₄(aq)) BaSO₄(s)","BaCO₃(s) →(conc. H₂SO₄) BaSO₄(s)","BaCO₃(s) →(HCl(aq)) →(H₂SO₄(aq)) BaSO₄(s)","BaCO₃(s) →(conc. HCl) BaCl₂(aq) →(Na₂SO₄(aq)) BaSO₄(s)"],"answerLetter":"C"},
//   {"id":1128,"subject":"化學","topic":"2A: Acids and Bases","type":"choice","text":"Which of the following statements about potassium hydroxide solution is INCORRECT?","points":5,"options":["When potassium hydroxide solution is added to iron(III) sulphate solution, a dirty green precipitate is formed.","When potassium hydroxide solution is heated with ammonium chloride solution, ammonia gas is liberated.","Dilute potassium hydroxide solution contains K⁺(aq) ions, H⁺(aq) ions and OH⁻(aq) ions.","Concentrated potassium hydroxide solution is corrosive."],"answerLetter":"A"},
