// {"id":1162,"subject":"化學","topic":"1. Planet Earth","type":"choice","text":"Which of the following statements concerning oxygen gas is correct?","points":5,"options":["Oxygen gas relights a glowing splint.","Oxygen gas turns moist pH paper red.","Oxygen gas turns moist pH paper blue.","Oxygen gas gives a 'pop' sound when tested with a burning splint."],"answerLetter":"A"},
