// {"id":1216,"subject":"化學","topic":"3. Metals","type":"choice","text":"Which of the following processes would NOT produce metal?","points":5,"options":["heating zinc oxide","heating copper(II) oxide with carbon","electrolysis of molten lithium chloride","heating iron(III) oxide with carbon monoxide"],"answerLetter":"A"},
